#include <stdfloat>
#include <vector>
#include <print>

int main() {
    // Simulate storing ML weights in bfloat16 vs float32
    std::vector<std::bfloat16_t> bf16_weights = {
        static_cast<std::bfloat16_t>(0.5f),
        static_cast<std::bfloat16_t>(-0.25f),
        static_cast<std::bfloat16_t>(1.0f),
        static_cast<std::bfloat16_t>(0.125f)
    };

    std::vector<std::float32_t> f32_weights = {0.5f, -0.25f, 1.0f, 0.125f};

    std::println("bfloat16 storage: {} bytes for 4 weights",
        bf16_weights.size() * sizeof(std::bfloat16_t));
    std::println("float32 storage:  {} bytes for 4 weights",
        f32_weights.size() * sizeof(std::float32_t));

    // Arithmetic works — convert to float32 for computation
    float sum = 0.0f;
    for (auto w : bf16_weights)
        sum += static_cast<float>(w);
    std::println("sum of bf16 weights: {}", sum);

    // Type system: float16_t and float32_t are distinct types
    auto f16 = static_cast<std::float16_t>(1.5f);
    std::float32_t f32 = 1.5f;
    std::println("float16_t == float32_t value: {}", static_cast<float>(f16) == f32);
}

#include <bit>
#include <cstdint>
#include <print>
#include <utility>

int main() {
    // Network byte order conversion (big-endian)
    uint32_t host_value = 0x12345678;
    uint32_t network_value = std::byteswap(host_value);

    std::println("host:    {:#010x}", host_value);
    std::println("network: {:#010x}", network_value);
    std::println("round-trip: {:#010x}", std::byteswap(network_value));

    // Works at compile time
    constexpr uint16_t port = std::byteswap(uint16_t{8080});
    std::println("port 8080 in network order: {:#06x}", port);

    // to_underlying
    enum class Status { OK = 200, NotFound = 404, Error = 500 };
    auto code = std::to_underlying(Status::NotFound);
    std::println("HTTP code: {}", code);
}

#include <utility>
#include <print>
#include <string_view>

enum class Direction { North, South, East, West };

std::string_view direction_name(Direction d) {
    switch (d) {
        case Direction::North: return "North";
        case Direction::South: return "South";
        case Direction::East:  return "East";
        case Direction::West:  return "West";
    }
    std::unreachable(); // all cases handled — helps optimizer skip default
}

int opposite_sign(int x) {
    if (x > 0) return 1;
    if (x < 0) return -1;
    return 0;
    // Note: no unreachable here — 0 is a valid path
}

int main() {
    for (auto d : {Direction::North, Direction::South, Direction::East, Direction::West})
        std::println("direction: {}", direction_name(d));

    std::println("sign(42): {}", opposite_sign(42));
    std::println("sign(-7): {}", opposite_sign(-7));
    std::println("sign(0): {}", opposite_sign(0));
}
